module adder_16bit(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] sum_low;
    wire [7:0] sum_high;
    wire carry;

    // Lower 8-bit adder
    assign {carry, sum_low} = a[7:0] + b[7:0] + Cin;

    // Upper 8-bit adder
    assign {Co, sum_high} = a[15:8] + b[15:8] + carry;

    // Concatenate the results
    assign y = {sum_high, sum_low};

endmodule
